import React, { useEffect, useMemo, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import MainLayout from "../components/3_Layout/MainLayout";

const QUICK_PROMPTS = [
  "오늘 너무 지쳤어",
  "취업 준비 때문에 불안해",
  "그냥 누가 먼저 말 걸어줬으면 좋겠어",
  "요즘 감정 패턴이 궁금해",
  "잡담도 할 수 있는 AI였으면 좋겠어",
];

const FEATURES = [
  {
    icon: "💬",
    title: "먼저 다가오는 대화",
    desc: "메이티는 사용자가 굳이 먼저 도움을 요청하지 않아도, 하루의 흐름과 분위기를 살피며 먼저 말을 건네는 능동형 AI 동반자예요.",
  },
  {
    icon: "🖥️",
    title: "화면 맥락 기반 공감",
    desc: "에러 화면, 채용 사이트, 오래 멈춘 문서 화면처럼 지금 보고 있는 맥락을 이해하고 상황에 맞는 말투로 반응해요.",
  },
  {
    icon: "📊",
    title: "감정 패턴 리포트",
    desc: "상담 기록과 반응 흐름을 바탕으로 고민 히스토리, 감정 분석, 하루 요약을 대시보드에서 한눈에 정리할 수 있어요.",
  },
  {
    icon: "🎭",
    title: "메이트 성격 커스터마이징",
    desc: "다정함, 차분함, 현실감, 장난기 같은 대화 톤을 조절해 나와 더 잘 맞는 메이트로 성장시킬 수 있어요.",
  },
  {
    icon: "🔐",
    title: "세밀한 보안 제어",
    desc: "모니터링 ON/OFF, 기록 저장 여부, 알림 강도 같은 민감한 기능을 사용자가 직접 제어할 수 있어 더 안심돼요.",
  },
  {
    icon: "🌐",
    title: "웹-앱 유기적 연결",
    desc: "데스크톱 앱에서 관계를 만들고, 웹 대시보드에서 감정 흐름과 설정을 관리하는 구조라 시연 임팩트도 확실해요.",
  },
];

const SCENARIOS = [
  {
    key: "error",
    label: "에러 화면",
    tag: "실시간 맥락 반응",
    title: "계속 안 풀리는 거 있어?",
    desc: "에러 창을 오래 보고 있을 때 메이티가 먼저 다가와 답답함을 같이 정리해줘요.",
    bubble: "계속 안 풀리는 거 있어? 잠깐 숨 돌리고 같이 볼까?",
  },
  {
    key: "job",
    label: "취업 준비",
    tag: "상황 맞춤 공감",
    title: "요즘 마음이 많이 지치지?",
    desc: "채용 사이트와 이력서를 오래 보고 있으면 긴장감과 피로를 알아채고 먼저 안부를 건네요.",
    bubble: "취업 준비 스트레스 많지? 잠깐 쉬면서 얘기해도 괜찮아.",
  },
  {
    key: "late",
    label: "늦은 밤",
    tag: "생활 루틴 케어",
    title: "오늘 하루 정리해볼까?",
    desc: "깊은 밤까지 혼자 작업하고 있을 때 하루의 감정 흐름을 자연스럽게 돌아볼 수 있도록 도와줘요.",
    bubble: "오늘 꽤 오래 버텼네. 지금 기분, 내가 조금 같이 정리해줄까?",
  },
];

const HOW_IT_WORKS = [
  {
    step: "01",
    title: "웹에서 계정을 만들어요",
