        <section className="matey-hero">
          <div className="matey-container">
            <div className="matey-hero__grid">
              <div className="matey-hero__copy">
                <span className="matey-badge">💜 먼저 알아봐 주는 AI 동반자, 메이티</span>

                <h1 className="matey-hero__title">
                  혼자 버티기 전에, <br />
                  <strong>먼저 다가오는 메이트</strong>
                </h1>

                <p className="matey-hero__desc">
                  메이티는 단순한 챗봇이 아니라, 바탕화면 가까이에서 함께 머물며
                  사용자의 상황과 감정 흐름을 먼저 살피는 AI 고민 상담 서비스예요.
                  다정하지만 맹목적이지 않고, 귀엽지만 가볍지 않은 하나의 동반자처럼
                  관계를 쌓아갑니다.
                </p>

                <div className="matey-search">
                  <form className="matey-search__form" onSubmit={handleSearchSubmit}>
                    <div className="matey-search__input-wrap">
                      <div className="matey-search__icon">🔎</div>
                      <input
                        className="matey-search__input"
                        value={heroInput}
                        onChange={(e) => setHeroInput(e.target.value)}
                        placeholder="오늘 마음이나 메이티에게 기대하는 걸 적어보세요"
                      />
                    </div>

                    <button
                      type="submit"
                      className="matey-btn matey-btn--primary matey-search__submit"
                    >
                      메이티 미리 보기
                    </button>
                  </form>

                  <div className="matey-search__chips">
                    {QUICK_PROMPTS.map((prompt) => (
                      <button
                        key={prompt}
                        type="button"
                        className="matey-chip"
                        onClick={() => handlePromptClick(prompt)}
                      >
                        {prompt}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="matey-hero__actions">
                  <button
                    type="button"
                    className="matey-btn matey-btn--primary"
                    onClick={() => moveTo("/signup")}
                  >
                    무료 체험 시작하기
                  </button>
                  <button
                    type="button"
                    className="matey-btn matey-btn--secondary"
                    onClick={() => moveTo("/download")}
                  >
                    데스크톱 다운로드
                  </button>
                </div>

                <div className="matey-hero__meta">
                  <div className="matey-meta-card">
                    <strong>능동형 상담</strong>
                    <span>사용자가 먼저 요청하지 않아도 먼저 다가와요</span>
                  </div>
                  <div className="matey-meta-card">
                    <strong>웹-앱 연동</strong>
                    <span>데스크톱 경험과 대시보드가 유기적으로 연결돼요</span>
                  </div>
                  <div className="matey-meta-card">
                    <strong>감정 리포트</strong>
                    <span>고민 히스토리와 하루 요약을 한눈에 볼 수 있어요</span>
                  </div>
                </div>
              </div>

              <div className="matey-hero__visual">
                <div className="matey-orb matey-orb--a" />
                <div className="matey-orb matey-orb--b" />
                <div className="matey-orb matey-orb--c" />

                <div className="matey-stage">
                  <div className="matey-stage__top">
                    <div className="matey-stage__pill">✨ Matey Desktop Active</div>
                    <div className="matey-stage__status">바탕화면에서 먼저 함께하는 중</div>
                  </div>

                  <div className="matey-stage__image-wrap">
                    <img
                      src="/images/rabbit-duo.png"
                      alt="메이티 토끼 듀오"
                      className="matey-stage__image-main"
                    />
                    <img
                      src="/images/rabbit.png"
                      alt="메이티 토끼"
                      className="matey-pet matey-pet--rabbit"
                    />
                    <img
                      src="/images/cat.png"
                      alt="메이티 고양이"
                      className="matey-pet matey-pet--cat"
                    />

                    <div className="matey-bubble matey-bubble--left">
                      오늘 조금 지쳐 보여요. <br />
                      잠깐 쉬어가도 괜찮아요.
                    </div>

                    <div className="matey-bubble matey-bubble--right">
                      {heroInput || "그냥 누가 먼저 말 걸어줬으면 좋겠어"}
                    </div>
                  </div>

                  <div className="matey-stage__footer">
                    <div className="matey-mini-card">
                      <strong>대화내역</strong>
                      <span>오늘의 고민과 감정 흐름을 자연스럽게 정리</span>
                    </div>
                    <div className="matey-mini-card">
                      <strong>보안설정</strong>
                      <span>모니터링 ON/OFF와 기록 저장 여부 직접 제어</span>
                    </div>
                    <div className="matey-mini-card">
                      <strong>개인설정</strong>
                      <span>메이트 성격과 말투를 나에게 맞게 조정</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </section>

        <section id="intro" className="matey-section is-soft">
          <div className="matey-container">
            <div className="matey-section-head">
              <span className="matey-badge">🌷 메이티가 특별한 이유</span>
              <h2 className="matey-section-title">
                검색엔진 같은 AI가 아니라, <br />
                관계를 만드는 메이트
              </h2>
              <p className="matey-section-desc">
                메이티는 무조건적인 위로나 기능 나열보다, 실제 사람처럼 다가오는 관계감에
                집중합니다. 귀엽고 부드럽지만, 필요할 땐 현실적이고 차분하게 대화해요.
              </p>
            </div>

            <div className="matey-feature-grid">
              {FEATURES.map((feature) => (
                <article key={feature.title} className="matey-feature-card">
                  <div className="matey-feature-card__icon">{feature.icon}</div>
                  <h3>{feature.title}</h3>
                  <p>{feature.desc}</p>
                </article>
              ))}
            </div>
          </div>
        </section>

        <section id="chat-demo" className="matey-section">
          <div className="matey-container">
            <div className="matey-section-head">
              <span className="matey-badge">🫧 상황 맞춤 대화 데모</span>
              <h2 className="matey-section-title">
                메이티는 이렇게 먼저 말을 걸어요
              </h2>
              <p className="matey-section-desc">
                단순한 챗봇처럼 사용자가 먼저 켜는 구조가 아니라, 사용자의 맥락과 상태를
                읽고 자연스럽게 먼저 관심을 보이는 경험을 설계합니다.
              </p>
            </div>

            <div className="matey-demo">
              <div className="matey-demo__menu">
                <h3>상황 시나리오</h3>
                <p>
                  발표 시연에서는 아래와 같은 화면 맥락을 기준으로 메이티가 먼저 다가오는
                  흐름을 보여주면 설득력이 훨씬 커집니다.
                </p>

                <div className="matey-scenario-list">
                  {SCENARIOS.map((scenario) => (
                    <button
                      key={scenario.key}
                      type="button"
                      className={`matey-scenario ${
                        activeScenario === scenario.key ? "is-active" : ""
                      }`}
                      onClick={() => setActiveScenario(scenario.key)}
                    >
                      <div className="matey-scenario__tag">{scenario.tag}</div>
                      <strong>{scenario.label}</strong>
                      <span>{scenario.desc}</span>
                    </button>
                  ))}
                </div>
              </div>

              <div className="matey-demo__panel">
                <div className="matey-chat-window">
                  <div className="matey-chat-window__top">
                    <div className="matey-chat-window__profile">
                      <div className="matey-chat-window__avatar">🐰</div>
                      <div>
                        <div className="matey-chat-window__name">메이티</div>
                        <div className="matey-chat-window__role">
                          먼저 말을 걸어주는 AI 동반자
                        </div>
                      </div>
                    </div>
                    <div className="matey-chat-window__state">{currentScenario.label}</div>
                  </div>

                  <div className="matey-chat">
                    <div className="matey-msg matey-msg--bot">
                      {currentScenario.bubble}
                    </div>

                    <div className="matey-msg matey-msg--user">
                      {heroInput || "그냥 누가 먼저 말 걸어줬으면 좋겠어"}
                    </div>

                    <div className="matey-msg matey-msg--bot">
                      무조건 괜찮다고만 하진 않을게요. 지금 많이 지친 것 같다면
                      잠깐 멈춰서 정리하는 게 먼저일 수도 있어요. 필요하면 오늘 감정
                      흐름도 같이 돌아볼까요?
                    </div>
                  </div>

                  <div className="matey-chat-input">
                    <input
                      value={heroInput}
                      onChange={(e) => setHeroInput(e.target.value)}
                      placeholder="메이티와 대화를 시작해보세요"
                    />
                    <button type="button" aria-label="전송">
                      ➜
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </section>

        <section className="matey-section is-soft" id="how-it-works">
          <div className="matey-container">
            <div className="matey-section-head">
              <span className="matey-badge">🪄 어떻게 작동하나요?</span>
              <h2 className="matey-section-title">
                메이티는 웹과 데스크톱을 하나의 경험으로 연결해요
              </h2>
              <p className="matey-section-desc">
                흔한 웹 챗봇이 아니라, 데스크톱 앱과 웹 대시보드가 함께 작동하는 구조라
                발표 시 데모 임팩트도 크고 서비스 완성도도 높아 보입니다.
              </p>
            </div>

            <div className="matey-how-grid">
              {HOW_IT_WORKS.map((item) => (
                <article key={item.step} className="matey-how-card">
                  <div className="matey-how-card__step">{item.step}</div>
                  <h3>{item.title}</h3>
                  <p>{item.desc}</p>
                </article>
              ))}
            </div>
          </div>
        </section>

        <section id="pricing" className="matey-section">
          <div className="matey-container">
            <div className="matey-section-head">
              <span className="matey-badge">💸 Pricing</span>
              <h2 className="matey-section-title">
                가볍게 시작하고, 더 깊게 연결하세요
              </h2>
              <p className="matey-section-desc">
                무료 체험부터 시작해도 괜찮고, 메이티의 진짜 강점은 기록과 분석, 그리고
                관계감이 쌓일수록 더 잘 드러납니다.
              </p>
            </div>

            <div className="matey-pricing-grid">
              {PLANS.map((plan) => (
                <article
                  key={plan.name}
                  className={`matey-price-card ${plan.highlight ? "is-highlight" : ""}`}
                >
                  {plan.badge && <div className="matey-price-card__badge">{plan.badge}</div>}
                  <h3>{plan.name}</h3>
                  <div className="matey-price-card__price">{plan.price}</div>
                  <p>{plan.desc}</p>

                  <ul>
                    {plan.features.map((feature) => (
                      <li key={feature}>{feature}</li>
                    ))}
                  </ul>

                  <div style={{ marginTop: "22px" }}>
                    <button
                      type="button"
                      className={`matey-btn ${
                        plan.highlight ? "matey-btn--primary" : "matey-btn--secondary"
                      }`}
                      onClick={() => moveTo("/signup")}
                    >
                      {plan.highlight ? "이 플랜으로 시작하기" : "무료 체험하기"}
                    </button>
                  </div>
                </article>
              ))}
            </div>
          </div>
        </section>

        <section id="faq" className="matey-section is-soft">
          <div className="matey-container">
            <div className="matey-section-head">
              <span className="matey-badge">❔ 도움말</span>
              <h2 className="matey-section-title">
                메이티를 시작하기 전 자주 묻는 질문
              </h2>
              <p className="matey-section-desc">
                프라이버시, 대화 스타일, 관리자 기능, 웹-앱 연동 구조처럼 발표와 시연에서
                자주 질문받는 포인트를 먼저 정리해두면 훨씬 안정적입니다.
              </p>
            </div>

            <div className="matey-faq">
              {FAQS.map((item, index) => {
                const isOpen = openFaq === index;
                return (
                  <div key={item.q} className="matey-faq-item">
                    <button type="button" onClick={() => setOpenFaq(isOpen ? -1 : index)}>
                      <span>{item.q}</span>
                      <span>{isOpen ? "−" : "+"}</span>
                    </button>
                    {isOpen && (
                      <div className="matey-faq-item__answer">
                        {item.a}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        </section>

        <section className="matey-section" id="download-banner">
          <div className="matey-container">
            <div className="matey-banner">
              <div>
                <span className="matey-badge">🐾 웹에서 시작하고 데스크톱에서 더 가까이</span>
                <h2>
                  메이티를 다운로드하고,
                  <br />
                  바탕화면에서 함께 살아가는 경험을 시작해보세요
                </h2>
                <p>
                  웹에서는 감정 리포트와 설정을 관리하고, 데스크톱에서는 먼저 다가오는
                  메이티와 실제 관계를 쌓아갈 수 있어요. 단순한 AI 툴이 아니라,
                  하루 가까이 머무는 동반자로 설계해보세요.
                </p>
              </div>

              <div className="matey-banner__actions">
                <button
                  type="button"
                  className="matey-btn matey-btn--primary"
                  onClick={() => moveTo("/download")}
                >
                  다운로드 페이지로
                </button>
                <button
                  type="button"
                  className="matey-btn matey-btn--secondary"
                  onClick={() => moveTo("/signup")}
                >
                  무료 체험 시작
                </button>
              </div>
            </div>
          </div>
        </section>
      </div>
    </MainLayout>
  );
};

export default HomePage;
